#include <bits/stdc++.h>
using namespace std; 
stack<int> p;
int n=500,m,d[502],g[502][502];
void Read(){
	cin>>m;
	for(int i=1;i<=m;i++){
		int u,v;
		cin>>u>>v;
		g[u][v]++,g[v][u]++;
		d[u]++,d[v]++;
	}
}
void dfs(int x){
	for(int i=1;i<=n;i++)
		while(g[x][i]){
			g[x][i]--,g[i][x]--;
			dfs(i);
		}
	p.push(x);
}
void Solve(){
	int x=0,f=0,y=0;
	for(int i=1;i<=n;i++){
		if(d[i] && !f)
			f=i;
		if(d[i]%2==1){
			y++;
			if(!x)
				x=i;
		}
	}
	if(y)
		dfs(x);
	else
		dfs(f);
	while(p.size()){
		cout<<p.top()<<endl;
		p.pop();
	}
}
int main(){
	Read();
	Solve();
	return 0;
}
